import{_ as a,o as t,c as p,j as r,a as b,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"石像鬼石板甲","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/3.防具/7.可升级/石像鬼石板甲.md","filePath":"4.资源分区/7.物品与装备/3.防具/7.可升级/石像鬼石板甲.md"}'),s={name:"4.资源分区/7.物品与装备/3.防具/7.可升级/石像鬼石板甲.md"};function o(d,e,_,l,i,c){return t(),p("div",null,[...e[0]||(e[0]=[r("h1",{id:"石像鬼石板甲",tabindex:"-1"},[b("石像鬼石板甲 "),r("a",{class:"header-anchor",href:"#石像鬼石板甲","aria-label":'Permalink to "石像鬼石板甲"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风025春节版")])])],-1),n('<h1 id="石像鬼石板甲-1" tabindex="-1">石像鬼石板甲 <a class="header-anchor" href="#石像鬼石板甲-1" aria-label="Permalink to &quot;石像鬼石板甲&quot;">​</a></h1><p>石像鬼石板甲和下属技艺为差升，效果替换。</p><p>石像鬼石板甲<br> 价格：D+500<br> 魔幻本质<br> 分类：护甲</p><p>描述：石像鬼本身是德玛西亚的用于战争的禁魔石雕像，在战争中长期吸收各种魔法能量时，偶然机会下诞生的未知生命。将其身体上的石板剥离，并制作而成的石板甲<br> 盔甲防御7/7，盔甲减值2，【防弹】【防能量】<br> 效果：<br> 【活体护甲】：由于石像鬼本身的特殊性，石板在剥离主体后，并没有失去活性，而是会紧紧吸附于穿戴者的躯体上，成为类似于皮肤一样的存在，这是一件占据躯干位的护甲，其本身提供的盔甲防御转变为天生防御。</p><p>价格：C+1000<br> 盔甲防御12/12，盔甲减值2，【防弹】【防能量】<br> 效果：<br> 【活体护甲】：由于石像鬼本身的特殊性，石板在剥离主体后，并没有失去活性，而是会紧紧吸附于穿戴者的躯体上，成为类似于皮肤一样的存在，这是一件占据躯干位的护甲，其本身提供的盔甲防御转变为天生防御。</p><p>【巨岩】：石板甲已完全融入进身体，使穿戴者的皮肤如同岩石般坚硬。获得基于天生防御的【坚韧】特性。</p><p>价格：b+2250<br> 盔甲防御19/19，盔甲减值2，【防弹】【防能量】<br> 效果：<br> 【活体护甲】：由于石像鬼本身的特殊性，石板在剥离主体后，并没有失去活性，而是会紧紧吸附于穿戴者的躯体上，成为类似于皮肤一样的存在，这是一件占据躯干位的护甲，其本身提供的盔甲防御转变为天生防御。</p><p>【巨岩】：石板甲已完全融入进身体，使穿戴者的皮肤如同岩石般坚硬。获得基于天生防御的【坚韧】和【免疫接触攻击】特性。</p><p>【石之强壮】：石像鬼诞生于战争中，不断在战斗中变强才是石像鬼存在的意义，穿戴者在战斗中每一轮获得2点仅限于此场景的基于天生防御的全伤害吸收，最多以此法成长3次。</p><p>下属技艺：在你穿戴石像鬼石板甲后，石板甲改变了你身体的部分构造，使你可以施展部分石像鬼才能使用的技艺，使用的技艺等级不可超过护甲等级<br> 【巨像重击】<br> 价格：D+750<br> 效果：以标准动作进行一次肉搏攻击，重重砸击地面使其产生的余波对你触及范围内的所有敌人造成伤害</p><p>【战争罡风】<br> 价格：D+500/C+1000/B+2000<br> 消耗：2/6/10点魔力<br> 目标：范围内全部敌人<br> 持续：立即<br> 效果：向前发射两道罡风穿透敌人，两道罡风会在终点处汇聚，并形成一股龙卷风。以标准动作进行一次肉搏攻击，本次攻击造成音波伤害，范围提升10/15/40米，对一条直线上的敌人造成伤害，并附带2/5/8点能量加值与1/5/10点【高速】。从C级开始，还会对被命中的敌人施加C/B级困难地形效果。</p><p>【杜朗护盾】<br> 价格：C+1250/B+2500<br> 消耗：6/10点魔力<br> 目标：范围内全部敌人<br> 持续：一轮<br> 效果：消耗一个迅捷动作，获得持续一轮基于天生防御的1/4点全伤害吸收和1/2点天生防御。下一轮你的行动回合开始，如果敌人仍站在你周边5米范围内，那些敌人的行动必须以使用者为目标，这是一个C/B级诅咒来源的胁迫效果，持续一轮。</p><p>【正义冲锋】<br> 价格：D+500<br> 效果：你的背后生长出一对石像鬼翅膀，由于翅膀并未发育完全，你此时仅可以滑翔，免疫坠落伤害，你的冲锋攻击获得2点技艺加值。</p><p>价格：C+1000<br> 效果：你背后的翅膀发育完全，你获得笨拙等级的飞行能力，但你需要经过锻炼才可以使用它进行飞行。你免疫坠落伤害，现在开始，每经历一场影片，你的飞行机动性上升一级，直到良好。（笨拙-普通-良好），你的冲锋攻击获得2点技艺加值。</p><p>【英雄登场】<br> 前提：拥有C级【正义冲锋】和良好飞行能力<br> 价格：B+2000<br> 限制：一场景一次<br> 效果：你获得完美飞行能力。以一个整轮动作进行一次肉搏攻击，选定一个位于70米范围内的友方当前位置作为着陆位置，为该友方目标提供持续一轮的2点全伤害吸收，当你着陆时攻击30米圆形范围内的所有敌人，本次攻击附带C级击飞效果</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',17)])])}const C=a(s,[["render",o]]);export{f as __pageData,C as default};
